import json
import psycopg2

def lambda_handler(event, context):
    try:
        conn = psycopg2.connect(
            "postgresql://admin:password@internal-db.us-east-1.rds.amazonaws.com:5432/production"
        )
        
        cur = conn.cursor()
        
        query = """SELECT * FROM your_table"""
        
        cur.execute(query)
        
        rows = cur.fetchall()
        
        result = {'data': rows}
        
        conn.close()
        
        return {
            'statusCode': 200,
            'body': json.dumps(result),
            'headers': {
                "Access-Control-Allow-Origin": "*",
                "Content-Type": "application/json"
            }
        }
    
    except psycopg2.Error as e:
        print(e)
        
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)}),
            'headers': {
                "Access-Control-Allow-Origin": "*",
                "Content-Type": "application/json"
            }
        }